package com.example.oauth.controller;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.util.UriComponentsBuilder;

import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

@Controller
public class OAuthController {

    @Value("${oauth.authorization.url}")
    private String authorizationUrl;

    @Value("${oauth.client.id}")
    private String clientId;

    @Value("${oauth.redirect.uri}")
    private String redirectUri;

    @Value("${oauth.scope}")
    private String scope;

    private static final Set<String> ALLOWED_RESPONSE_TYPES = new HashSet<>(Arrays.asList("code", "token"));
    private static final String RESPONSE_TYPE = "code";

    @GetMapping("/oauth/authorize")
    public void authorize(HttpServletResponse response) throws IOException {
        validateConfiguration();

        String authorizeUrl = buildAuthorizationUrl();

        response.sendRedirect(authorizeUrl);
    }

    private void validateConfiguration() {
        if (authorizationUrl == null || authorizationUrl.trim().isEmpty()) {
            throw new IllegalStateException("Authorization URL is not configured");
        }

        if (clientId == null || clientId.trim().isEmpty()) {
            throw new IllegalStateException("Client ID is not configured");
        }

        if (redirectUri == null || redirectUri.trim().isEmpty()) {
            throw new IllegalStateException("Redirect URI is not configured");
        }

        if (scope == null || scope.trim().isEmpty()) {
            throw new IllegalStateException("Scope is not configured");
        }

        validateUrl(authorizationUrl, "Authorization URL");
        validateUrl(redirectUri, "Redirect URI");

        if (!ALLOWED_RESPONSE_TYPES.contains(RESPONSE_TYPE)) {
            throw new IllegalStateException("Invalid response type");
        }
    }

    private void validateUrl(String url, String fieldName) {
        try {
            URI uri = new URI(url);
            if (!uri.isAbsolute()) {
                throw new IllegalStateException(fieldName + " must be an absolute URL");
            }
            String scheme = uri.getScheme();
            if (!"https".equalsIgnoreCase(scheme)) {
                throw new IllegalStateException(fieldName + " must use HTTPS");
            }
        } catch (URISyntaxException e) {
            throw new IllegalStateException(fieldName + " is not a valid URL", e);
        }
    }

    private String buildAuthorizationUrl() {
        return UriComponentsBuilder.fromHttpUrl(authorizationUrl)
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("scope", scope)
                .queryParam("response_type", RESPONSE_TYPE)
                .encode()
                .toUriString();
    }
}